message.content:
Let me search more specifically for park-related projects completed in 2022:

<tool_calls>
[
  {
    "tool": "query_db",
    "args": {
      "db_name": "civic_docs_database",
      "query": "{\"collection\": \"civic_docs\", \"filter\": {\"text\": {\"$regex\": \"park.*2022.*completed|completed.*2022.*park\", \"$options\": \"i\"}}, \"projection\": {\"_id\": 1, \"filename\": 1, \"text\": 1}}"
    }
  }
]
</tool_calls>

<tool_calls>
[
  {
    "tool": "query_db",
    "args": {
      "db_name": "funding_database",
      "query": "SELECT * FROM Funding WHERE Project_Name LIKE '%park%' OR Project_Name LIKE '%Park%'"
    }
  }
]
</tool_calls>
